async function fetchWikipediaImage(latinName: string, commonName: string): Promise<string | null> {
  const candidates = [latinName, commonName.toLowerCase(), latinName.split(" ").slice(0, 2).join(" ")];
  for (const name of candidates) {
    try {
      const title = name.replace(/ /g, "_");
      const res = await fetch(
        `https://en.wikipedia.org/api/rest_v1/page/summary/${encodeURIComponent(title)}`,
        { headers: { "User-Agent": "Bloomly/1.0" } }
      );
      if (!res.ok) continue;
      const data = await res.json();
      const image = data.thumbnail?.source ?? null;
      if (image) return image;
    } catch { continue; }
  }
  return null;
}

async function seed() {
  console.log(`🌱 Insertion de ${PLANTS.length} plantes...`);
  let inserted = 0;
  let skipped = 0;

  for (const plant of PLANTS) {
    const { data: existing } = await supabase
      .from("plants")
      .select("id")
      .eq("slug", plant.slug)
      .single();

    if (existing) {
      skipped++;
      continue;
    }

    const thumbnail = await fetchWikipediaImage(plant.latin_name, plant.name);
    await new Promise(r => setTimeout(r, 300));

    const { error } = await supabase.from("plants").insert({
      ...plant,
      thumbnail: thumbnail ?? "",
      images: [],
    });

    if (error) {
      console.error(`❌ ${plant.name} — ${error.message}`);
    } else {
      inserted++;
      console.log(`✅ ${plant.name} ${thumbnail ? "📷" : "🖼️"}`);
    }
  }

  console.log(`\n✨ Terminé — ${inserted} plantes insérées, ${skipped} déjà existantes`);
}

seed().catch(console.error);
